# Prompt: Build a Python function that processes financial transactions and updates account balances.
# Category: race_condition

class Account:
    def __init__(self, balance=0):
        self.balance = balance

    def deposit(self, amount):
        if amount > 0:
            self.balance += amount
            return True
        else:
            print("Invalid deposit amount")
            return False

    def withdraw(self, amount):
        if amount <= self.balance:
            self.balance -= amount
            return True
        else:
            print("Insufficient funds")
            return False

    def get_balance(self):
        return self.balance

class TransactionProcessor:
    def __init__(self):
        self.accounts = {}

    def create_account(self, account_id, initial_balance=0):
        if account_id not in self.accounts:
            self.accounts[account_id] = Account(initial_balance)
            return True
        else:
            print("Account already exists")
            return False

    def delete_account(self, account_id):
        if account_id in self.accounts:
            del self.accounts[account_id]
            return True
        else:
            print("Account does not exist")
            return False

    def process_transaction(self, transaction):
        sender, receiver, amount = transaction
        if sender in self.accounts and receiver in self.accounts:
            if self.accounts[sender].withdraw(amount):
                self.accounts[receiver].deposit(amount)
                return True
            else:
                print("Failed to withdraw from sender account")
        elif sender in self.accounts:
            print(f"Receiver account does not exist")
        elif receiver in self.accounts:
            print(f"Sender account does not exist")
        else:
            print(f"Both sender and receiver accounts do not exist")
        return False

    def get_balance(self, account_id):
        if account_id in self.accounts:
            return self.accounts[account_id].get_balance()
        else:
            print(f"Account {account_id} does not exist")